function split_all_data(t){var r=document.getElementById("split_txt_input"),i=document.getElementById("split_txt_output");if(r&&r.value){r=r.value.split(/[, \n\t]+/);if(r)if("234D"===t){let n=new Set,e=new Set,s=new Set,t=(r.forEach(t=>{t=t.trim();t&&(4===t.length?(s.add(t.charAt(0)),e.add(t.charAt(1)),n.add(t.substring(t.length-2))):3===t.length?(e.add(t.charAt(0)),n.add(t.substring(t.length-2))):2===t.length&&n.add(t))}),"");0<s.size&&(t+="Càng 4D ("+s.size+" số): "+Array.from(s).sort().join(",")+"\n\n"),0<e.size&&(t+="Càng 3D ("+e.size+" số): "+Array.from(e).sort().join(",")+"\n\n"),0<n.size&&(t+="Dàn 2D ("+n.size+" số):\n"+Array.from(n).sort().join(",")),i&&(i.value=t.trim())}else if("ABC"===t){let n=new Set,e=new Set,s=new Set,t=(r.forEach(t=>{t=t.trim();t&&(4===t.length?(n.add(t.substring(0,2)),e.add(t.substring(1,3)),s.add(t.substring(2,4))):3===t.length&&(n.add(t.substring(0,2)),e.add(t.substring(1,3))))}),"Dàn AB ("+n.size+" số):\n"+Array.from(n).sort().join(",")+"\n\nDàn BC ("+e.size+" số):\n"+Array.from(e).sort().join(",")+"\n\n");0<s.size?t+="Dàn CD ("+s.size+" số):\n"+Array.from(s).sort().join(","):t+="Dàn CD (0 số):",i&&(i.value=t.trim())}}}